solution:
public class Main {
    public static void main(String[] args) {
        String word = "racecar";
        String reversed = "";
        for (int i = word.length() - 1; i >= 0; i--) {
            reversed += word.substring(i, i + 1);
        }
        System.out.println(reversed);
        System.out.println(word.equals(reversed));
    }
}

