public class Main {
    public static void main(String[] args) {
        String sentence = "AP Computer Science A is awesome";
        int spaces = 0;
        for (int i = 0; i < sentence.length(); i++) {
            if (sentence.substring(i, i + 1).equals(" ")) {
                spaces++;
            }
        }
        int words = spaces + 1;
        System.out.println(words);
    }
}

